function gcd(a, b):
  while b != 0:
    a, b = b, a % b
  return a

function gcd(a, b):
  t = min(a, b)
  while t > 0:
    if a % t == 0 and b % t == 0: return t
    t = t - 1

function gcd(a, b):
  factorsA = primeFactorization(a)
  factorsB = primeFactorization(b)
  common = intersection(factorsA, factorsB)
  return product(common)

function factorial(n):
  if n == 0 or n == 1: return 1
  return n * factorial(n - 1)
